/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // Adjacency list for the graph
    // adj[u] stores neighbors of u: [v, cost, tax] for the edge (u, v)
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Since roads are bidirectional
        // Edge u -> v
        adj[u].push({ to: v, cost: cost, tax: tax });
        // Edge v -> u
        adj[v].push({ to: u, cost: cost, tax: tax });
    }

    // --- Step 1: Calculate shortest path distances for 'going' (empty hands) ---
    // dist_empty[i][j]: minimum cost to go from i to j with empty hands.
    // Cost per edge (u, v) = cost.
    const INF = Number.MAX_SAFE_INTEGER;
    const distEmpty = Array(n).fill(0).map(() => Array(n).fill(INF));

    for (let i = 0; i < n; i++) {
        distEmpty[i][i] = 0;
        // Dijkstra from source i using cost only
        const distances = Array(n).fill(INF);
        distances[i] = 0;
        // Priority Queue: [distance, node]
        const pq = [[0, i]]; 

        while (pq.length > 0) {
            // Simple priority queue implementation (since N is small enough, O(N^2) Dijkstra is okay, 
            // but let's stick to PQ logic for correctness/efficiency if possible, though array sort is easiest here)
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.to;
                const weight = edge.cost; // Empty hand cost
                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }

        // Store results for source i
        for (let j = 0; j < n; j++) {
            distEmpty[i][j] = distances[j];
        }
    }

    // --- Step 2: Calculate shortest path distances for 'returning' (carrying apples) ---
    // dist_taxed[i][j]: minimum cost to return from i to j while carrying apples.
    // Cost per edge (u, v) = cost * tax.
    const distTaxed = Array(n).fill(0).map(() => Array(n).fill(INF));

    for (let i = 0; i < n; i++) {
        distTaxed[i][i] = 0;
        // Dijkstra from source i using cost * tax
        const distances = Array(n).fill(INF);
        distances[i] = 0;
        // Priority Queue: [distance, node]
        const pq = [[0, i]]; 

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.to;
                // Calculate taxed cost for the edge (u, v)
                const taxed_weight = edge.cost * edge.tax; 
                if (distances[u] + taxed_weight < distances[v]) {
                    distances[v] = distances[u] + taxed_weight;
                    pq.push([distances[v], v]);
                }
            }
        }

        // Store results for source i
        for (let j = 0; j < n; j++) {
            distTaxed[i][j] = distances[j];
        }
    }

    // --- Step 3: Calculate the minimum cost for each shop i ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at shop i
        let minCost = prices[i];

        // Option 2: Go to shop j (buy apples), then return to shop i.
        // Total cost = Price[j] + Travel_Empty(i -> j) + Travel_Taxed(j -> i)
        // Note: The problem states: 
        // - Go from i (empty) -> j (buy)
        // - Return from j (with apples) -> i
        // The total path is i --(empty)--> j --(taxed)--> i

        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            const priceJ = prices[j];
            const travelEmpty_ij = distEmpty[i][j];
            const travelTaxed_ji = distTaxed[j][i];

            // Check if paths exist
            if (travelEmpty_ij !== INF && travelTaxed_ji !== INF) {
                // Total cost = Price[j] + Cost(i->j, empty) + Cost(j->i, taxed)
                const totalCost = priceJ + travelEmpty_ij + travelTaxed_ji;
                minCost = Math.min(minCost, totalCost);
            }
        }

        ans[i] = minCost;
    }

    return ans;
}

